// frontend/src/lib/auth/tokenUtils.ts

import { userApi } from '@/lib/api/endpoints';

/**
 * Get the JWT token from cookies or localStorage
 * @returns The JWT token string or null if not found
 */
export const getToken = (): string | null => {
  if (typeof document === 'undefined') return null; // For SSR compatibility

  // First try to get from cookies
  const value = `; ${document.cookie}`;
  const parts = value.split('; jwt_token=');
  if (parts.length === 2) {
    const token = parts.pop()?.split(';').shift();
    if (token) return token;
  }

  // Fallback to localStorage
  try {
    return localStorage.getItem('jwt_token');
  } catch (e) {
    return null;
  }
};

/**
 * Set the JWT token in cookies and localStorage
 * @param token The JWT token to store
 */
export const setToken = (token: string): void => {
  if (typeof document === 'undefined') return; // For SSR compatibility

  // Set cookie with expiration (7 days)
  const expires = new Date();
  expires.setTime(expires.getTime() + 7 * 24 * 60 * 60 * 1000); // 7 days

  document.cookie = `jwt_token=${token};expires=${expires.toUTCString()};path=/;SameSite=Strict`;

  // Also store in localStorage as fallback
  try {
    localStorage.setItem('jwt_token', token);
  } catch (e) {
    // localStorage might not be available in some browsers
  }
};

/**
 * Remove the JWT token from cookies and localStorage
 */
export const removeToken = (): void => {
  if (typeof document === 'undefined') return; // For SSR compatibility

  // Set cookie with past date to delete it
  document.cookie = 'jwt_token=;expires=Thu, 01 Jan 1970 00:00:00 GMT;path=/';

  // Also remove from localStorage
  try {
    localStorage.removeItem('jwt_token');
  } catch (e) {
    // localStorage might not be available in some browsers
  }
};

/**
 * Check if the user is authenticated by verifying token existence
 * @returns Boolean indicating if user is authenticated
 */
export const isAuthenticated = (): boolean => {
  const token = getToken();
  return token !== null && token !== '';
};

/**
 * Get the user ID from the JWT token
 * @returns The user ID string or null if not found
 */
export const getUserIdFromToken = (): string | null => {
  const token = getToken();
  if (!token) return null;

  try {
    // Decode JWT token (without verification)
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map(c => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );

    const decoded = JSON.parse(jsonPayload);
    return decoded.userId || decoded.user_id || decoded.sub || null;
  } catch (error) {
    console.error('Error decoding token:', error);
    return null;
  }
};

/**
 * Sign in function to authenticate user and store token
 * @param email User's email
 * @param password User's password
 * @returns Promise that resolves when sign in is complete
 */
export const signIn = async (email: string, password: string): Promise<any> => {
  try {
    // Note: This assumes you have an auth API endpoint
    // You might need to adjust this based on your actual auth API
    const response = await fetch(`${process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000'}/auth/login`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ email, password }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({ message: 'Login failed' }));
      throw new Error(errorData.detail || errorData.message || 'Login failed');
    }

    const data = await response.json();

    // Assuming the response contains the JWT token
    if (data.access_token) {
      setToken(data.access_token);
      return data;
    } else {
      throw new Error('Token not found in response');
    }
  } catch (error) {
    console.error('Sign in error:', error);
    throw error;
  }
};

/**
 * Sign out function to remove token
 * @returns Promise that resolves when sign out is complete
 */
export const signOut = async (): Promise<void> => {
  try {
    // Optionally call backend to invalidate token
    await fetch(`${process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000'}/api/auth/logout`, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${getToken()}`,
        'Content-Type': 'application/json',
      },
    }).catch(() => {}); // Ignore errors during logout

    removeToken();
  } catch (error) {
    console.error('Sign out error:', error);
    removeToken(); // Still remove local token even if backend call fails
  }
};

/**
 * Register function to create a new user
 * @param email User's email
 * @param password User's password
 * @param firstName User's first name (optional)
 * @param lastName User's last name (optional)
 * @returns Promise that resolves when registration is complete
 */
export const register = async (
  email: string,
  password: string,
  firstName?: string,
  lastName?: string
): Promise<any> => {
  try {
    const response = await fetch(`${process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000'}/auth/register`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ email, password, firstName, lastName }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({ message: 'Registration failed' }));
      throw new Error(errorData.detail || errorData.message || 'Registration failed');
    }

    const data = await response.json();

    // Assuming the response contains the JWT token
    if (data.access_token) {
      setToken(data.access_token);
      return data;
    } else {
      throw new Error('Token not found in response');
    }
  } catch (error) {
    console.error('Registration error:', error);
    throw error;
  }
};

/**
 * Get user profile function
 * @returns Promise that resolves with user profile data
 */
export const getUser = async (): Promise<any> => {
  try {
    // Using the userApi from endpoints.ts
    const userData = await userApi.getProfile();
    return userData;
  } catch (error) {
    console.error('Get user error:', error);
    throw error;
  }
};