// frontend/src/lib/api/client.ts

import axios from 'axios';

const apiClient = axios.create({
  baseURL: process.env.NEXT_PUBLIC_API_BASE_URL || 'http://localhost:8000',
  headers: {
    'Content-Type': 'application/json',
  },
});

// Helper function to get cookie value by name
const getCookie = (name: string): string | undefined => {
  if (typeof document === 'undefined') return undefined; // For SSR compatibility

  const value = `; ${document.cookie}`;
  const parts = value.split(`; ${name}=`);
  if (parts.length === 2) return parts.pop()?.split(';').shift();
  return undefined;
};

// Helper function to get token from localStorage (fallback)
const getLocalStorageToken = (): string | null => {
  if (typeof window !== 'undefined') {
    return window.localStorage.getItem('jwt_token');
  }
  return null;
};

// Add a request interceptor to include the auth token
apiClient.interceptors.request.use(
  (config) => {
    // Retrieve the token from cookies first, then fallback to localStorage
    let token = getCookie('jwt_token');
    
    if (!token) {
      token = getLocalStorageToken();
    }

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Add a response interceptor to handle errors globally if needed
apiClient.interceptors.response.use(
  (response) => {
    return response;
  },
  (error) => {
    // Handle global error responses here if needed
    console.error('API Error:', error);
    return Promise.reject(error);
  }
);

export default apiClient;