import apiClient from './client';

// User-related API functions
export const userApi = {
  // Get current user's profile
  getProfile: async () => {
    try {
      const response = await apiClient.get('/auth/me');
      return response.data;
    } catch (error: any) {
      console.error('Error fetching user profile:', error);

      // Check if it's a network error
      if (error.code === 'ERR_NETWORK') {
        console.error('Network error: Could not connect to the server. Please make sure the backend is running.');
        throw new Error('Could not connect to the server. Please make sure the backend is running.');
      }
      
      // Check if it's an authentication error
      if (error.response?.status === 401) {
        console.error('Authentication error: Please log in to access profile.');
        throw new Error('Authentication failed. Please log in again.');
      }

      throw error;
    }
  },

  // Update user profile
  updateProfile: async (userData: any) => {
    try {
      const response = await apiClient.put('/api/auth/profile', userData);
      return response.data;
    } catch (error: any) {
      console.error('Error updating user profile:', error);

      // Check if it's a network error
      if (error.code === 'ERR_NETWORK') {
        console.error('Network error: Could not connect to the server. Please make sure the backend is running.');
        throw new Error('Could not connect to the server. Please make sure the backend is running.');
      }
      
      // Check if it's an authentication error
      if (error.response?.status === 401) {
        console.error('Authentication error: Please log in to update profile.');
        throw new Error('Authentication failed. Please log in again.');
      }

      throw error;
    }
  }
};

